import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.DocumentBuilder;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import org.w3c.dom.Node;
import java.util.HashMap;
import java.util.Map;

public class XMLParser {
    public Map<String, String> parse(String xml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(new org.xml.sax.InputSource(new java.io.StringReader(xml)));

        Map<String, String> settings = new HashMap<>();
        NodeList configNodes = document.getElementsByTagName("configuration");
        if (configNodes != null && configNodes.getLength() > 0) {
            for (int i = 0; i < configNodes.getLength(); ++i) {
                Node node = configNodes.item(i);
                if (node.getNodeType() == Node.ELEMENT_NODE && "configuration".equals(node.getNodeName())) {
                    NodeList settingsNodes = node.getChildNodes();
                    for (int j = 0; j < settingsNodes.getLength(); ++j) {
                        Node settingNode = settingsNodes.item(j);
                        if (settingNode.getNodeType() == Node.ELEMENT_NODE && settingNode.getNodeName().contains("setting")) {
                            String key = settingNode.getAttributes().getNamedItem("key").getTextContent();
                            String value = settingNode.getTextContent();
                            settings.put(key, value);
                        }
                    }
                }
            }
        }
        return settings;
    }
}